VALUES
  ('dietitian-moex-00583', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '王小姐平日吃素，每日攝取 1,100 卡熱量以控制體重。依素食飲食指標建議，王小姐飲食中的未 精製全穀雜糧類應占全穀雜糧類的比例為何？', '["1/4", "1/3", "1/2", "2/3"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00584', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列為每日飲食指南對油脂與堅果種子類的攝取建議，何者正確？', '["1份堅果種子約1茶匙量", "油脂與堅果種子類每份含5公克脂肪", "堅果種子類，含有利於健康的必需營養素與植化素，攝取份數可不受限", "減少「飽和脂肪酸」，增加「多元不飽和脂肪酸」及適量「單元不飽和脂肪酸」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00585', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列那一類產品的營養標示，不是以包裝食品營養標示應遵行事項為依據？', '["以維生素、礦物質為營養添加劑之發泡錠產品", "市售包裝嬰兒與較大嬰兒配方食品", "特定疾病的配方食品", "健康食品"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00586', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '第八版國人膳食營養素參考攝取量（DRIs）嬰兒期年齡別，每公斤體重熱量或營養素需求量，下 列何者正確？', '["脂肪：0～6個月＜7～12個月", "蛋白質：0～6個月＜7～12個月", "熱量：0～6個月＞7～12個月", "碳水化合物：0～6個月＞7～12個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00587', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於「國際母乳代用品銷售守則」規範，下列何者錯誤？', '["禁止向公眾廣告母乳代用品", "禁止免費向母親提供產品", "向保健工作者提供之資料必須具有當地族群的研究資料", "禁止以文字或圖畫的形式宣傳人工餵養，包含在產品標籤上印嬰兒圖片"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00588', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關常用於老年人的整合性營養評估工具迷你營養評估（MiniNutritionalAssessment,MNA）和美 國的DETERMINE，下列敘述何者正確？', '["MNA簡易版有6題，可由一般照顧者及醫療人員使用，完整版有18題，包含飲食評估，須由 營養師來執行", "MNA的內容包括體位測量（身高、體重和體重變化）、一般性評估（生活型態、藥物使用和行 動力）、飲食評估（進食餐次、食物與液體攝入量）及主觀性評估（水腫、腹水）", "DETERMINE的內容共有9項影響老年人營養健康最常見的危險因子，包括疾病、吃不好、掉 牙或口腔疼痛、經濟困難、社交接觸減少、服用多種藥物、不自主體重減輕／增加、自我照顧 需要協助、年齡超過80歲", "與MNA相比，DETERMINE對於體重變化有較高的敏感度與精確度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00589', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '長期照顧十年計畫2.0中，建立社區為基礎發展連續多目標服務體系，分為A級：社區整合型服務 中心，B級：複合型服務中心，C級：巷弄長照站，其中可提供營養餐飲服務（共餐或送餐）為：', '["僅A級", "僅B、C級", "A、B、C級", "僅C級"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00590', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據學校衛生法，有關學校衛生管理工作，下列敘述何者錯誤？', '["學校每月應至少檢查餐飲場所1次，並予記錄", "學校檢查餐飲場所紀錄應保存3年", "各級教育主管機關應會同農業及衛生主管機關定期抽查學校餐飲衛生，每學年至少1次", "學校餐飲衛生管理均應符合食品之良好衛生規範準則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00591', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據幼兒園餐點食物內容及營養基準，幼兒園供餐內容，下列何者錯誤？', '["全穀雜糧類，未精製應占1/3以上", "每週至少供應1份魚類", "每兩天供應1份鮮奶、原味優酪乳、保久乳", "蔬菜類供應，深色蔬菜應超過1/3"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00592', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據勞動基準法，有關孕婦保護措施相關規定，下列敘述何者正確？', '["女工分娩前後，應停止工作，給予產假4星期", "女工分娩前後停止工作，若受僱工作在6個月以上者，停止工作期間薪資減半發給", "女工妊娠3個月以上流產者，應停止工作，給予產假4星期", "子女未滿1歲須女工親自哺乳者，除規定休息時間外，雇主應每日另給哺乳時間3次，每次以 30分鐘為度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
